 28	import {
 29	  userFeedbackClose,
 30	  userFeedbackOpen,
 31	  userFeedbackSetSentiment,
 32	  userFeedbackSetText,
 33	} from '../redux-actions';
 34	import { State } from '../redux-reducers';
 35	import { Attachment } from '../types';
 36	import CloseButton from './CloseButton';
 37	import CopyAction from './CopyAction';
 38	import ErrorBoundary from './ErrorBoundary';
 39	
 40	const USER_FEEDBACK_ENDPOINT = getApiUrl('/v1/feedback');
 41	
 42	const REQUEST_TIMEOUT = 5 * 60 * 1000;
 43	
 44	const THUMBS_DOWN = -1;
 45	const THUMBS_UP = 1;
 46	
 47	type Props = {
 48	  conversationID: string;
 49	  entryIndex: number;
 50	};
 51	
 52	const Feedback: React.FC<Props> = ({ conversationID, entryIndex }) => {
 53	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
 54	
 55	  const dispatch = useDispatch();
 56	
 57	  const isOpen: string = useSelector((s: State) =>
 58	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'userFeedback', 'isOpen']),
 59	  );
 60	  const query: string = useSelector((s: State) =>
 61	    s.plugins?.ols?.getIn(['chatHistory', entryIndex - 1, 'text']),
 62	  );
 63	  const attachments: ImmutableMap<string, Attachment> = useSelector((s: State) =>
 64	    s.plugins?.ols?.getIn(['chatHistory', entryIndex - 1, 'attachments']),
 65	  );
 66	  const response: string = useSelector((s: State) =>
 67	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'text']),
 68	  );
 69	  const sentiment: number = useSelector((s: State) =>
 70	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'userFeedback', 'sentiment']),
 71	  );
 72	  const text: string = useSelector((s: State) =>
 73	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'userFeedback', 'text']),
 74	  );
 75	
 76	  const [error, setError] = React.useState<ErrorType>();
 77	  const [submitted, setSubmitted] = React.useState(false);
 78	
 79	  const onClose = React.useCallback(() => {
 80	    dispatch(userFeedbackClose(entryIndex));
 81	  }, [dispatch, entryIndex]);
 82	
 83	  const onThumbsDown = React.useCallback(() => {
 84	    dispatch(userFeedbackOpen(entryIndex));
 85	    dispatch(
 86	      userFeedbackSetSentiment(entryIndex, sentiment === THUMBS_DOWN ? undefined : THUMBS_DOWN),
 87	    );
 88	  }, [dispatch, entryIndex, sentiment]);
 89	
 90	  const onThumbsUp = React.useCallback(() => {
 91	    dispatch(userFeedbackOpen(entryIndex));
 92	    dispatch(userFeedbackSetSentiment(entryIndex, sentiment === THUMBS_UP ? undefined : THUMBS_UP));
 93	  }, [dispatch, entryIndex, sentiment]);
 94	
 95	  const onTextChange = React.useCallback(
 96	    (_e, newText) => {
 97	      dispatch(userFeedbackSetText(entryIndex, newText));
 98	    },
 99	    [dispatch, entryIndex],
100	  );
101	
102	  const onSubmit = React.useCallback(() => {
103	    const userQuestion = attachments
104	      ? `${query}\n---\nThe attachments that were sent with the prompt are shown below.\n${JSON.stringify(attachments.valueSeq().map(toOLSAttachment), null, 2)}`
105	      : query;
106	
107	    /* eslint-disable camelcase */
108	    const requestJSON = {
109	      conversation_id: conversationID,
110	      llm_response: response,
111	      sentiment,
112	      user_feedback: text,
113	      user_question: userQuestion,
