138	          >
139	            {sentiment === THUMBS_UP ? <ThumbsUpIcon /> : <OutlinedThumbsUpIcon />}
140	          </div>
141	        </Tooltip>
142	        <Tooltip content={t('Bad response')}>
143	          <div
144	            className={`ols-plugin__response-action${
145	              sentiment === THUMBS_DOWN ? ' ols-plugin__response-action--selected' : ''
146	            }`}
147	            onClick={onThumbsDown}
148	          >
149	            {sentiment === THUMBS_DOWN ? <ThumbsDownIcon /> : <OutlinedThumbsDownIcon />}
150	          </div>
151	        </Tooltip>
152	        <CopyAction className="ols-plugin__response-action" value={response} />
153	        {isOpen && sentiment !== undefined && (
154	          <div className="ols-plugin__feedback-comment">
155	            <Title headingLevel="h3">
156	              <CloseButton onClose={onClose} />
157	              {t('Why did you choose this rating?')}{' '}
158	              <Label variant="outline">{t('Optional')}</Label>
159	            </Title>
160	            <TextArea
161	              aria-label={t('Provide additional feedback')}
162	              className="ols-plugin__feedback-input"
163	              onChange={onTextChange}
164	              placeholder={t('Provide additional feedback')}
165	              resizeOrientation="vertical"
166	              rows={1}
167	              value={text}
168	            />
169	            <HelperText>
170	              <HelperTextItem className="ols-plugin__feedback-footer" variant="indeterminate">
171	                {t(
172	                  "Do not include personal information or other sensitive information in your feedback. Feedback may be used to improve Red Hat's products or services.",
173	                )}
174	              </HelperTextItem>
