 18	  OutlinedThumbsDownIcon,
 19	  OutlinedThumbsUpIcon,
 20	  ThumbsDownIcon,
 21	  ThumbsUpIcon,
 22	} from '@patternfly/react-icons';
 23	
 24	import { toOLSAttachment } from '../attachments';
 25	import { getApiUrl } from '../config';
 26	import { ErrorType, getFetchErrorMessage } from '../error';
 27	import { getRequestInitWithAuthHeader } from '../hooks/useAuth';
 28	import {
 29	  userFeedbackClose,
 30	  userFeedbackOpen,
 31	  userFeedbackSetSentiment,
 32	  userFeedbackSetText,
 33	} from '../redux-actions';
 34	import { State } from '../redux-reducers';
 35	import { Attachment } from '../types';
 36	import CloseButton from './CloseButton';
 37	import CopyAction from './CopyAction';
 38	import ErrorBoundary from './ErrorBoundary';
 39	
 40	const USER_FEEDBACK_ENDPOINT = getApiUrl('/v1/feedback');
 41	
 42	const REQUEST_TIMEOUT = 5 * 60 * 1000;
 43	
 44	const THUMBS_DOWN = -1;
 45	const THUMBS_UP = 1;
 46	
 47	type Props = {
 48	  conversationID: string;
 49	  entryIndex: number;
 50	};
 51	
 52	const Feedback: React.FC<Props> = ({ conversationID, entryIndex }) => {
 53	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
 54	
 55	  const dispatch = useDispatch();
 56	
 57	  const isOpen: string = useSelector((s: State) =>
 58	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'userFeedback', 'isOpen']),
 59	  );
 60	  const query: string = useSelector((s: State) =>
 61	    s.plugins?.ols?.getIn(['chatHistory', entryIndex - 1, 'text']),
 62	  );
 63	  const attachments: ImmutableMap<string, Attachment> = useSelector((s: State) =>
 64	    s.plugins?.ols?.getIn(['chatHistory', entryIndex - 1, 'attachments']),
 65	  );
 66	  const response: string = useSelector((s: State) =>
 67	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'text']),
 68	  );
 69	  const sentiment: number = useSelector((s: State) =>
 70	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'userFeedback', 'sentiment']),
 71	  );
 72	  const text: string = useSelector((s: State) =>
 73	    s.plugins?.ols?.getIn(['chatHistory', entryIndex, 'userFeedback', 'text']),
 74	  );
 75	
 76	  const [error, setError] = React.useState<ErrorType>();
 77	  const [submitted, setSubmitted] = React.useState(false);
 78	
 79	  const onClose = React.useCallback(() => {
 80	    dispatch(userFeedbackClose(entryIndex));
 81	  }, [dispatch, entryIndex]);
 82	
 83	  const onThumbsDown = React.useCallback(() => {
 84	    dispatch(userFeedbackOpen(entryIndex));
 85	    dispatch(
 86	      userFeedbackSetSentiment(entryIndex, sentiment === THUMBS_DOWN ? undefined : THUMBS_DOWN),
 87	    );
 88	  }, [dispatch, entryIndex, sentiment]);
 89	
 90	  const onThumbsUp = React.useCallback(() => {
 91	    dispatch(userFeedbackOpen(entryIndex));
 92	    dispatch(userFeedbackSetSentiment(entryIndex, sentiment === THUMBS_UP ? undefined : THUMBS_UP));
 93	  }, [dispatch, entryIndex, sentiment]);
 94	
 95	  const onTextChange = React.useCallback(
 96	    (_e, newText) => {
 97	      dispatch(userFeedbackSetText(entryIndex, newText));
 98	    },
 99	    [dispatch, entryIndex],
100	  );
101	
102	  const onSubmit = React.useCallback(() => {
103	    const userQuestion = attachments
104	      ? `${query}\n---\nThe attachments that were sent with the prompt are shown below.\n${JSON.stringify(attachments.valueSeq().map(toOLSAttachment), null, 2)}`
105	      : query;
106	
107	    /* eslint-disable camelcase */
108	    const requestJSON = {
109	      conversation_id: conversationID,
110	      llm_response: response,
111	      sentiment,
112	      user_feedback: text,
113	      user_question: userQuestion,
114	    };
115	    /* eslint-enable camelcase */
116	
117	    consoleFetchJSON
118	      .post(USER_FEEDBACK_ENDPOINT, requestJSON, getRequestInitWithAuthHeader(), REQUEST_TIMEOUT)
119	      .then(() => {
120	        dispatch(userFeedbackClose(entryIndex));
121	        setSubmitted(true);
122	      })
123	      .catch((err) => {
124	        setError(getFetchErrorMessage(err, t));
125	        setSubmitted(false);
126	      });
127	  }, [conversationID, dispatch, entryIndex, query, attachments, response, sentiment, t, text]);
128	
129	  return (
130	    <>
131	      <div className="ols-plugin__feedback">
132	        <Tooltip content={t('Good response')}>
133	          <div
134	            className={`ols-plugin__response-action${
135	              sentiment === THUMBS_UP ? ' ols-plugin__response-action--selected' : ''
136	            }`}
137	            onClick={onThumbsUp}
138	          >
139	            {sentiment === THUMBS_UP ? <ThumbsUpIcon /> : <OutlinedThumbsUpIcon />}
140	          </div>
141	        </Tooltip>
142	        <Tooltip content={t('Bad response')}>
143	          <div
144	            className={`ols-plugin__response-action${
145	              sentiment === THUMBS_DOWN ? ' ols-plugin__response-action--selected' : ''
146	            }`}
147	            onClick={onThumbsDown}
148	          >
149	            {sentiment === THUMBS_DOWN ? <ThumbsDownIcon /> : <OutlinedThumbsDownIcon />}
150	          </div>
151	        </Tooltip>
152	        <CopyAction className="ols-plugin__response-action" value={response} />
153	        {isOpen && sentiment !== undefined && (
154	          <div className="ols-plugin__feedback-comment">
155	            <Title headingLevel="h3">
156	              <CloseButton onClose={onClose} />
157	              {t('Why did you choose this rating?')}{' '}
158	              <Label variant="outline">{t('Optional')}</Label>
159	            </Title>
160	            <TextArea
161	              aria-label={t('Provide additional feedback')}
162	              className="ols-plugin__feedback-input"
163	              onChange={onTextChange}
164	              placeholder={t('Provide additional feedback')}
165	              resizeOrientation="vertical"
166	              rows={1}
167	              value={text}
168	            />
169	            <HelperText>
170	              <HelperTextItem className="ols-plugin__feedback-footer" variant="indeterminate">
171	                {t(
172	                  "Do not include personal information or other sensitive information in your feedback. Feedback may be used to improve Red Hat's products or services.",
173	                )}
174	              </HelperTextItem>
175	            </HelperText>
176	            {error && (
177	              <Alert
178	                className="ols-plugin__alert"
179	                isExpandable={!!error.moreInfo}
180	                isInline
181	                title={error.moreInfo ? error.message : t('Error submitting feedback')}
182	                variant="danger"
183	              >
184	                {error.moreInfo ? error.moreInfo : error.message}
185	              </Alert>
186	            )}
187	            <Button onClick={onSubmit} variant="primary">
188	              {t('Submit')}
189	            </Button>
190	          </div>
191	        )}
192	      </div>
193	      {submitted && (
194	        <Label className="ols-plugin__feedback-submitted" color="blue">
195	          {t('Thank you for your feedback!')}
196	        </Label>
197	      )}
198	    </>
199	  );
200	};
201	
202	const FeedbackWithErrorBoundary: React.FC<Props> = ({ conversationID, entryIndex }) => (
203	  <ErrorBoundary>
204	    <Feedback conversationID={conversationID} entryIndex={entryIndex} />
205	  </ErrorBoundary>
206	);
207	
208	export default FeedbackWithErrorBoundary;
